const a={klipperscreenStudio:{intro:{t:0,b:{t:2,i:[{t:3}],s:"Edita de forma segura la configuración de la pantalla táctil KlipperScreen de tu impresora y reinicia KlipperScreen para aplicarla. Cada guardado se respalda primero."}},help:{title:{t:0,b:{t:2,i:[{t:3}],s:"Cómo funciona"}},body:{t:0,b:{t:2,i:[{t:3}],s:"KlipperScreen.conf controla la pantalla táctil conectada a tu impresora — tema, idioma, menús y opciones de visualización. Este editor lee y escribe ese archivo por la misma ruta segura que el Editor de Config."}},step1:{t:0,b:{t:2,i:[{t:3}],s:"Edita el texto de configuración abajo (o déjalo igual)."}},step2:{t:0,b:{t:2,i:[{t:3}],s:"Guardar — el archivo se respalda primero, y el guardado se rechaza mientras la impresora está ocupada."}},step3:{t:0,b:{t:2,i:[{t:3}],s:"Reinicia KlipperScreen para aplicar el cambio en la pantalla física."}},lfNote:{t:0,b:{t:2,i:[{t:3}],s:"Las líneas usan finales UNIX (LF), aplicados automáticamente al guardar."}}},status:{checking:{t:0,b:{t:2,i:[{t:3}],s:"Buscando KlipperScreen…"}},absent:{t:0,b:{t:2,i:[{t:3}],s:"No se detectó KlipperScreen en esta impresora (sin KlipperScreen.conf, y no reportado por Moonraker). Instala KlipperScreen para usar esta herramienta."}},present:{t:0,b:{t:2,i:[{t:3}],s:"KlipperScreen detectado"}},theme:{t:0,b:{t:2,i:[{t:3}],s:"Tema"}},language:{t:0,b:{t:2,i:[{t:3}],s:"Idioma"}},notRestartable:{t:0,b:{t:2,i:[{t:3}],s:"Moonraker no puede reiniciar KlipperScreen automáticamente — reinícialo manualmente tras guardar."}}},editor:{loading:{t:0,b:{t:2,i:[{t:3}],s:"Leyendo KlipperScreen.conf…"}},reload:{t:0,b:{t:2,i:[{t:3}],s:"Recargar"}},save:{t:0,b:{t:2,i:[{t:3}],s:"Guardar config"}},saving:{t:0,b:{t:2,i:[{t:3}],s:"Guardando…"}},saved:{t:0,b:{t:2,i:[{t:3}],s:"Guardado (respaldado)"}},unsaved:{t:0,b:{t:2,i:[{t:3}],s:"Cambios sin guardar"}}},save:{busy:{t:0,b:{t:2,i:[{t:3}],s:"Rechazado mientras la impresora está ocupada — inténtalo cuando esté inactiva."}},stale:{t:0,b:{t:2,i:[{t:3}],s:"KlipperScreen.conf cambió en disco desde que se cargó (probablemente editado en la pantalla). Recarga antes de guardar para no sobrescribir ese cambio."}}},view:{config:{t:0,b:{t:2,i:[{t:3}],s:"Config"}},themes:{t:0,b:{t:2,i:[{t:3}],s:"Temas"}}},themes:{loading:{t:0,b:{t:2,i:[{t:3}],s:"Cargando temas…"}},palette:{t:0,b:{t:2,i:[{t:3}],s:"Paleta"}},radius:{t:0,b:{t:2,i:[{t:3}],s:"Radio de esquina"}},preview:{t:0,b:{t:2,i:[{t:3}],s:"Vista previa en vivo"}},btn:{t:0,b:{t:2,i:[{t:3}],s:"Botón"}},previewWarn:{t:0,b:{t:2,i:[{t:3}],s:"aviso"}},previewApprox:{t:0,b:{t:2,i:[{t:3}],s:"Vista previa aproximada — la pantalla real se dibuja con GTK; se esperan diferencias menores."}},namePlaceholder:{t:0,b:{t:2,i:[{t:3}],s:"Nombre del nuevo tema"}},createApply:{t:0,b:{t:2,i:[{t:3}],s:"Crear y aplicar"}},createOnly:{t:0,b:{t:2,i:[{t:3}],s:"Solo crear"}},installed:{t:0,b:{t:2,i:[{t:3}],s:"Temas instalados"}},apply:{t:0,b:{t:2,i:[{t:3}],s:"Aplicar"}},delete:{t:0,b:{t:2,i:[{t:3}],s:"Eliminar tema"}},generated:{t:0,b:{t:2,i:[{t:3}],s:"Creado aquí"}},created:{t:0,b:{t:2,i:[{t:3}],s:"Tema creado. Aplícalo desde la lista y reinicia."}},appliedRestart:{t:0,b:{t:2,i:[{t:3}],s:"Tema establecido — reinicia KlipperScreen para verlo."}}},restart:{button:{t:0,b:{t:2,i:[{t:3}],s:"Reiniciar KlipperScreen"}},restarting:{t:0,b:{t:2,i:[{t:3}],s:"Reiniciando…"}},done:{t:0,b:{t:2,i:[{t:3}],s:"KlipperScreen se está reiniciando — la pantalla se recargará pronto."}},confirmTitle:{t:0,b:{t:2,i:[{t:3}],s:"¿Reiniciar KlipperScreen?"}},confirmBody:{t:0,b:{t:2,i:[{t:3}],s:"Esto reinicia el servicio de la pantalla táctil para aplicar tus cambios. No afecta una impresión activa, pero la pantalla se apagará unos segundos."}},confirm:{t:0,b:{t:2,i:[{t:3}],s:"Reiniciar"}},cancel:{t:0,b:{t:2,i:[{t:3}],s:"Cancelar"}}}}};export{a as default};
